import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"乌云踏雪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/4.B级/乌云踏雪.md","filePath":"4.资源分区/7.物品与装备/3.防具/4.B级/乌云踏雪.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/4.B级/乌云踏雪.md"};function d(l,a,_,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"乌云踏雪",tabindex:"-1"},[n("乌云踏雪 "),e("a",{class:"header-anchor",href:"#乌云踏雪","aria-label":'Permalink to "乌云踏雪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="乌云踏雪-1" tabindex="-1">乌云踏雪 <a class="header-anchor" href="#乌云踏雪-1" aria-label="Permalink to &quot;乌云踏雪&quot;">​</a></h1><p>乌云踏雪<br> 魔幻本质<br> 价格：B+3000</p><p>分类：重甲</p><p>盔甲防御：24/24</p><p>盔甲减值：3</p><p>描述：漆黑的玄铁为原料，千锻而成的数千枚甲叶组成的全身重甲，为守卫边疆而制作。<br> 千北寒，天地寂，乌云踏雪行。</p><p>魂于冰雪：乌云踏雪会为使用者提供基于盔甲防御的【超级坚韧】，以及【免疫接触攻击】的效果，这是某种意义上盔甲上的守卫之魂与你融合的结果。</p><p>于边境的风暴中：乌云踏雪甲叶构成的防护极其全面，但也取决于使用者的意志，乌云踏雪具有【封闭1】，在这基础上，使用者每具有1点传奇决心，乌云踏雪便额外提升1层【封闭】。</p><p>雪中行：穿戴乌云踏雪且知道当前地区的气象情况时，穿戴者可以以一个自由动作激发守卫之魂，将场地的天气引导向更寒冷的方向。但这一能力有所限制，比如说只能将阴天引导为细雨，或将细雨引导为细雪等，也就是前后环境效果必须接近且改变较为细微，这个效果每个场景只能使用一次。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
